    #[func]
    pub fn first(
        &self,
        /// If given, returns an array of the first `count` grapheme
        /// clusters instead of a single string.
        #[named]
        count: Option<usize>,
        /// A set of characters to remove from the start of the string
        /// before extracting, if given.
        #[named]
        strip: Option<Str>,
    ) -> StrResult<Value> {
        let stripped = match &strip {
            Some(pattern) => {
                self.0.trim_start_matches(|c| pattern.as_str().contains(c))
            }
            None => self.0.as_str(),
